const mapLineItem = (item, record) => {
  const lineItemPromise = {
    itemId: item.item_name,
    itemName: item.item_id,
    itemDesc: item.so_desc,
    orderedQty: parseFloat(item.so_quantity || 0),
    altUOM: item.so_item_uom || "",
    unitPrice: parseFloat(item.so_item_price || 0),
    custom_fields: item.custom_fields, // wzp 0530 edit
    soAmount: parseFloat(item.so_amount || 0),
    moreDesc: item.more_desc,
    lineRemark1: item.line_remark_1,
    lineRemark2: item.line_remark_2,
    lineRemark3: item.line_remark_3,
    deliveredQtyFromSource: parseFloat(item.delivered_qty || 0),
    original_so_id: String(record.id),
    so_no: record.so_no,
    so_line_item_id: String(item.id),
    item_category_id: String(item.item_category_id),
    plannedQtyFromSource: parseFloat(item.planned_qty || 0),
  };

  return lineItemPromise;
};

const mapGDLineItem = (item, record) => {
  const gdLinePromise = {
    material_id: item.item_name,
    material_name: item.item_id,
    gd_material_desc: item.so_desc,
    more_desc: item.more_desc,
    gd_order_quantity: parseFloat(item.so_quantity || 0),
    gd_order_uom_id: item.so_item_uom || "",
    good_delivery_uom_id: item.so_item_uom || "",
    line_so_no: record.so_no,
    so_line_item_id: String(item.id),
    line_so_id: String(record.id),
    item_category_id: String(item.item_category_id),
    line_remark_1: item.line_remark_1,
    line_remark_2: item.line_remark_2,
    line_remark_3: item.line_remark_3,
  };

  return gdLinePromise;
};

