const gdConvertType = {{workflowparams:gd_type}};
const soData = {{node:search_node_ZidRIRxa.data.data}};
const plantID = {{workflowparams:plant_id}};

let gdData = [];
if (gdConvertType === "multiple") {
  for (const [index, record] of soData.entries()) {
    let lineItemPromises = [];
    let gdLineItemPromises = [];

    for (const item of record.table_so) {
      const lineItemPromise = mapLineItem(item, record);
      const gdLinePromise = mapGDLineItem(item, record);
      lineItemPromises.push(lineItemPromise);
      gdLineItemPromises.push(gdLinePromise);
    }

    const mappedData = mapHeaderData(
      record,
      record.so_no,
      'draft',
      [record.id],
      JSON.stringify(lineItemPromises),
      plantID,
      gdLineItemPromises
    );

    gdData.push(mappedData);
  }
} else {
  let lineItemPromises = [];
  for (const record of soData) {
    for (const item of record.table_so) {
      const lineItemPromise = mapLineItem(item, record);
      lineItemPromises.push(lineItemPromise);
    }
  }
