  const record = soData[0];
  const soNo = soData.map((item) => item.so_no).join(", ");
  const soID = soData.map((item) => item.id);
  const gdPrefix = "";
  const mappedData = mapHeaderData(
    record,
    soNo,
    gdPrefix,
    soID,
    JSON.stringify(lineItemPromises),
    plantID,
    []
  );

  gdData.push(mappedData);
}

return gdData;
